from datetime import datetime

def gecen_dakika(baslangic, bitis):
    baslangic_dt = datetime.fromisoformat(baslangic)
    bitis_dt = datetime.fromisoformat(bitis)
    return int((bitis_dt - baslangic_dt).total_seconds() // 60)

print(gecen_dakika("2026-07-22T09:00:00", "2026-07-22T12:30:00+03:00"))
